CustomFunction.Calculation:
// Appends AND first operator second comparing two columns directly (no binding).
// Both first and second accept Table::Field references, GetFieldName() strings,
// or plain SQL expressions. Example: WHERE "Invoice"."id" = "LineItem"."invoiceId"
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqFirst = GetFieldName ( first ) ;
_first = QueryConvertField_cf ( If ( Position ( _fqFirst ; "::" ; 1 ; 1 ) > 0 ; _fqFirst ; first ) ) ;
_fqSecond = GetFieldName ( second ) ;
_second = QueryConvertField_cf ( If ( Position ( _fqSecond ; "::" ; 1 ; 1 ) > 0 ; _fqSecond ; second ) ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "column" ; JSONString ] ;
	[ "column" ; _first ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "second" ; _second ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)
